const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const convertCurrency = async (
  amount: number,
  fromCurrency: string,
  toCurrency: string
): Promise<ConversionResult> => {
  try {
    const prompt = `
      Convert ${amount} ${fromCurrency} to ${toCurrency}.
      You are a precise currency conversion engine.

      Requirements:
      1. Use the 'googleSearch' tool to find the absolute latest real-time exchange rate. This is critical.
      2. If the currency code is invalid or not a real currency, return an error.
      3. If the amount is negative or invalid, return an error.

      Output strictly valid JSON matching this schema:

      Success:
      {
        "converted_amount": number,
        "from_currency": "ISO Code",
        "to_currency": "ISO Code",
        "exchange_rate": number
      }

      Failure:
      {
        "error": "Description of error"
      }
    `;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            converted_amount: { type: Type.NUMBER },
            from_currency: { type: Type.STRING },
            to_currency: { type: Type.STRING },
            exchange_rate: { type: Type.NUMBER },
            error: { type: Type.STRING },
          },
        },
      },
    });

    const text = response.text;
    if (!text) {
      throw new Error("Empty response from AI");
    }

    const result = JSON.parse(text) as ConversionResult;
    return result;

  } catch (error) {
    console.error("Currency conversion failed:", error);
    return {
      error: "Failed to connect to conversion service. Please try again.",
    };
  }
};

