  const [toCurrency, setToCurrency] = useState<string>('EUR');

  const [result, setResult] = useState<ConversionResult | null>(null);
  const [loading, setLoading] = useState<boolean>(false);
  const [history, setHistory] = useState<ConversionHistoryItem[]>([]);
  const [showHistory, setShowHistory] = useState<boolean>(false);

  const handleSwap = () => {
    setFromCurrency(toCurrency);
    setToCurrency(fromCurrency);
    setResult(null); // Clear result on swap to force re-convert intent
  };

  const handleConvert = useCallback(async () => {
    if (amount <= 0) return;

    setLoading(true);
    setResult(null);

    try {
      const data = await convertCurrency(amount, fromCurrency, toCurrency);
      setResult(data);

      if ('converted_amount' in data) {
        const historyItem: ConversionHistoryItem = {
          ...data,
          id: Date.now().toString(),
          timestamp: Date.now(),
        };
        setHistory(prev => [historyItem, ...prev].slice(0, 10)); // Keep last 10
      }
    } catch (err) {
      console.error(err);
      setResult({ error: "An unexpected error occurred." });
    } finally {
      setLoading(false);
    }
  }, [amount, fromCurrency, toCurrency]);

  // Debounce conversion trigger or initial load? 
  // Requirement says "The app must accept user input... Convert button" usually implied 
  // but "Live" feeling is better. However, to save tokens/calls, let's stick to a manual trigger 
  // or a debounced effect if desired. Given the explicit "On Successful Conversion" output format,
  // manual trigger is safer and cleaner for an LLM-backed app.

