                  aria-label="Swap currencies"
                >
                  <ArrowDownUp className="w-5 h-5" />
                </button>
              </div>

              <CurrencySelector
                label="They get"
                value={toCurrency}
                onChange={setToCurrency}
                amount={result && 'converted_amount' in result ? result.converted_amount : 0}
                onAmountChange={() => {}} // Read only usually for target
                readOnlyAmount
                isLoading={loading}
              />
            </div>

            {/* Action Button */}
            <button
              onClick={handleConvert}
              disabled={loading || amount <= 0}
              className="w-full bg-blue-600 hover:bg-blue-700 disabled:bg-slate-300 disabled:cursor-not-allowed text-white font-semibold py-4 rounded-xl shadow-md transition-all flex items-center justify-center gap-2 text-lg"
