export interface Currency {
  code: string;
  name: string;
  flag: string;
}

export interface ConversionSuccess {
  converted_amount: number;
  from_currency: string;
  to_currency: string;
  exchange_rate: number;
  isCached?: boolean;
  timestamp?: number;
}

export interface ConversionErrorDetail {
  code: string;
  message: string;
}

export interface ConversionError {
  error: ConversionErrorDetail;
}

export type ConversionResult = ConversionSuccess | ConversionError;

export interface ConversionHistoryItem extends ConversionSuccess {
  id: string;
  timestamp: number;
}

import { GoogleGenAI, Type } from "@google/genai";
import { ConversionResult, ConversionSuccess } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const CACHE_PREFIX = 'gemini_currency_rate_';

interface CachedRate {
  rate: number;
  timestamp: number;
}

const getCacheKey = (from: string, to: string) => `${CACHE_PREFIX}${from}_${to}`;

const saveToCache = (from: string, to: string, rate: number) => {
  const data: CachedRate = { rate, timestamp: Date.now() };
  localStorage.setItem(getCacheKey(from, to), JSON.stringify(data));
};

const getFromCache = (from: string, to: string): CachedRate | null => {
  const json = localStorage.getItem(getCacheKey(from, to));
  if (!json) return null;
  try {
    return JSON.parse(json) as CachedRate;
  } catch (e) {
    return null;
  }
};

export const convertCurrency = async (
  amount: number,
  fromCurrency: string,
  toCurrency: string
): Promise<ConversionResult> => {
  // 1. Try Online Conversion if network is available
  if (navigator.onLine) {
    try {
      const prompt = `
        You are a strict currency conversion API for a mobile application.

        Task: Convert ${amount} ${fromCurrency} to ${toCurrency}.

        Instructions:
        1. Use 'googleSearch' to find the latest exchange rate.
        2. Validate inputs:
           - Amount must be numeric.
           - Currency codes must be valid ISO 4217.
        3. Output MUST be strict JSON.

        Schema for SUCCESS:
        {
          "converted_amount": <number>,
          "from_currency": "<ISO code>",
          "to_currency": "<ISO code>",
          "exchange_rate": <number>
        }

        Schema for FAILURE:
        {
          "error": {
            "code": "<INVALID_AMOUNT | UNSUPPORTED_CURRENCY | API_ERROR>",
            "message": "<English description>"
          }
        }
      `;

      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: {
          tools: [{ googleSearch: {} }],
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              converted_amount: { type: Type.NUMBER },
              from_currency: { type: Type.STRING },
              to_currency: { type: Type.STRING },
              exchange_rate: { type: Type.NUMBER },
              error: {
                type: Type.OBJECT,
                properties: {
                  code: { type: Type.STRING },
                  message: { type: Type.STRING }
                }
              }
            },
          },
        },
      });

      const text = response.text;
      if (!text) {
        throw new Error("Empty response from AI");
      }

      const result = JSON.parse(text) as ConversionResult;

      // If successful, cache the rates (forward and reverse)
      if ('exchange_rate' in result && typeof result.exchange_rate === 'number') {
        saveToCache(fromCurrency, toCurrency, result.exchange_rate);

        // Calculate and cache reverse rate if valid
        if (result.exchange_rate > 0) {
          saveToCache(toCurrency, fromCurrency, 1 / result.exchange_rate);
        }

        // Add timestamp to result
        (result as ConversionSuccess).timestamp = Date.now();
        (result as ConversionSuccess).isCached = false;
      }

      return result;

    } catch (error) {
      console.warn("Online conversion failed, attempting fallback:", error);
      // Fall through to offline logic
    }
  }

  // 2. Offline Fallback
  try {
    const cachedData = getFromCache(fromCurrency, toCurrency);

    if (cachedData) {
      return {
        converted_amount: amount * cachedData.rate,
        from_currency: fromCurrency,
        to_currency: toCurrency,
        exchange_rate: cachedData.rate,
        isCached: true,
        timestamp: cachedData.timestamp
      };
    }

    return {
      error: {
        code: navigator.onLine ? "API_ERROR" : "OFFLINE_NO_CACHE",
        message: navigator.onLine 
          ? "Service unavailable and no cached rate found." 
          : "You are offline and no cached rate was found for this pair."
      }
    };
  } catch (err) {
    return { 
      error: {
        code: "SYSTEM_ERROR",
        message: "An unexpected system error occurred."
      }
    };
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { ArrowDownUp, RefreshCw, History, AlertCircle, Info, WifiOff, Wifi, Globe, X } from 'lucide-react';
import { CurrencySelector } from './components/CurrencySelector';
import { convertCurrency } from './services/geminiService';
import { ConversionResult, ConversionHistoryItem } from './types';
import { POPULAR_CURRENCIES } from './constants';

const App: React.FC = () => {
  const [amount, setAmount] = useState<number>(1);
  const [fromCurrency, setFromCurrency] = useState<string>('USD');
  const [toCurrency, setToCurrency] = useState<string>('EUR');

  const [result, setResult] = useState<ConversionResult | null>(null);
  const [loading, setLoading] = useState<boolean>(false);
  const [history, setHistory] = useState<ConversionHistoryItem[]>([]);
  const [showHistory, setShowHistory] = useState<boolean>(false);
  const [showCurrencies, setShowCurrencies] = useState<boolean>(false);
  const [isOnline, setIsOnline] = useState<boolean>(navigator.onLine);

  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  const handleSwap = () => {
    setFromCurrency(toCurrency);
    setToCurrency(fromCurrency);
    setResult(null); // Clear result on swap to force re-convert intent
  };

  const handleConvert = useCallback(async () => {
    if (amount <= 0) return;

    setLoading(true);
    setResult(null);

    try {
      const data = await convertCurrency(amount, fromCurrency, toCurrency);
      setResult(data);

      if ('converted_amount' in data) {
        const historyItem: ConversionHistoryItem = {
          ...data,
          id: Date.now().toString(),
          timestamp: data.timestamp || Date.now(),
        };
        setHistory(prev => [historyItem, ...prev].slice(0, 10)); // Keep last 10
      }
    } catch (err) {
      console.error(err);
      setResult({ 
        error: { 
          code: "UNKNOWN", 
          message: "An unexpected error occurred." 
        } 
      });
    } finally {
      setLoading(false);
    }
  }, [amount, fromCurrency, toCurrency]);

  const formatTimestamp = (ts?: number) => {
    if (!ts) return '';
    return new Date(ts).toLocaleString(undefined, {
      month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit'
    });
  };

  return (
    <div className="min-h-screen bg-slate-100 flex items-start justify-center p-0 sm:p-4">
      <div className="w-full max-w-lg bg-white sm:rounded-3xl shadow-xl min-h-screen sm:min-h-[auto] flex flex-col">

        {/* Mobile Header */}
        <div className="bg-blue-600 text-white p-6 rounded-b-3xl sm:rounded-t-3xl sm:rounded-b-none shadow-lg z-10">
          <div className="flex justify-between items-start mb-4">
             <div>
               <h1 className="text-2xl font-bold">Converter</h1>
               <p className="text-blue-100 text-sm">Gemini AI Powered</p>
             </div>
             {!isOnline ? (
               <div className="bg-amber-500/20 backdrop-blur-sm border border-amber-300/30 p-2 rounded-lg">
                 <WifiOff className="w-5 h-5 text-amber-100" />
               </div>
             ) : (
               <div className="bg-blue-500/20 backdrop-blur-sm border border-blue-400/30 p-2 rounded-lg">
                 <Wifi className="w-5 h-5 text-blue-100" />
               </div>
             )}
          </div>

          <div className="flex gap-2">
            <button 
              onClick={() => setShowCurrencies(true)}
              className="flex items-center gap-1.5 px-3 py-1.5 bg-blue-700/50 hover:bg-blue-700 rounded-full text-xs font-medium transition-colors border border-blue-500/30"
            >
              <Globe className="w-3.5 h-3.5" />
              Supported Currencies
            </button>
          </div>
        </div>

        {/* Scrollable Content */}
        <div className="flex-1 overflow-y-auto p-6 space-y-6">

          {/* Input Section */}
          <div className="space-y-4 relative mt-2">
            <CurrencySelector
              label="You send"
              value={fromCurrency}
              onChange={setFromCurrency}
              amount={amount}
              onAmountChange={setAmount}
            />

            <div className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 z-10">
              <button
                onClick={handleSwap}
                className="bg-blue-600 hover:bg-blue-700 text-white p-3 rounded-full shadow-lg border-4 border-white transition-transform hover:rotate-180 hover:scale-105 active:scale-95"
                aria-label="Swap currencies"
              >
                <ArrowDownUp className="w-5 h-5" />
              </button>
            </div>

            <CurrencySelector
              label="They get"
              value={toCurrency}
              onChange={setToCurrency}
              amount={result && 'converted_amount' in result ? result.converted_amount : 0}
              onAmountChange={() => {}} 
              readOnlyAmount
              isLoading={loading}
            />
          </div>

          {/* Action Button */}
          <button
            onClick={handleConvert}
            disabled={loading || amount <= 0}
            className="w-full bg-blue-600 hover:bg-blue-700 disabled:bg-slate-300 disabled:cursor-not-allowed text-white font-semibold py-4 rounded-xl shadow-lg transition-all flex items-center justify-center gap-2 text-lg active:scale-[0.98]"
          >
            {loading ? (
              <>
                <RefreshCw className="w-5 h-5 animate-spin" />
                Updating...
              </>
            ) : (
              'Convert'
            )}
          </button>

          {/* Error Message */}
          {result && 'error' in result && (
            <div className="bg-red-50 border border-red-200 text-red-700 p-4 rounded-xl flex items-start gap-3 animate-in fade-in slide-in-from-bottom-2">
              <AlertCircle className="w-5 h-5 shrink-0 mt-0.5" />
              <div>
                <h4 className="font-semibold text-sm">Error: {result.error.code}</h4>
                <p className="text-sm opacity-90">{result.error.message}</p>
              </div>
            </div>
          )}

          {/* Result Info */}
          {result && 'converted_amount' in result && !loading && (
            <div className={`rounded-xl p-5 border animate-in fade-in slide-in-from-bottom-2 ${result.isCached ? 'bg-amber-50 border-amber-100' : 'bg-green-50 border-green-100'}`}>
              <div className="flex justify-between items-center mb-2">
                <span className="text-slate-500 text-xs font-medium uppercase tracking-wider">Exchange Rate</span>
                {result.isCached ? (
                    <span className="text-amber-700 bg-amber-100 px-2 py-0.5 rounded text-[10px] font-bold flex items-center gap-1">
                      OFFLINE
                    </span>
                ) : (
                  <span className="text-green-700 bg-green-100 px-2 py-0.5 rounded text-[10px] font-bold">
                    LIVE
                  </span>
                )}
              </div>
              <div className="text-xl text-slate-800 font-medium">
                1 {result.from_currency} = <span className="font-bold">{result.exchange_rate} {result.to_currency}</span>
              </div>
              <div className="text-[10px] text-slate-400 mt-2 flex items-center gap-1">
                <Info className="w-3 h-3" />
                {result.isCached 
                  ? `Last updated: ${formatTimestamp(result.timestamp)}` 
                  : 'Sourced via Google Search'}
              </div>
            </div>
          )}

          {/* History Toggle */}
          <button 
            onClick={() => setShowHistory(!showHistory)}
            className="flex items-center justify-between w-full p-4 bg-white border border-slate-200 rounded-xl hover:border-blue-300 transition-colors"
          >
            <div className="flex items-center gap-2 text-slate-700 font-medium">
              <History className="w-5 h-5 text-blue-600" />
              History
            </div>
            <span className="text-slate-400 text-sm">{history.length} items</span>
          </button>

          {/* History List */}
          {showHistory && (
             <div className="space-y-2 animate-in slide-in-from-top-2">
                {history.length === 0 ? (
                  <div className="text-center text-slate-400 text-sm py-4">
                    No history available.
                  </div>
                ) : (
                  history.map((item) => (
                    <div key={item.id} className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm flex justify-between items-center">
                       <div className="flex flex-col">
                          <span className="text-slate-900 font-semibold text-lg">
                            {item.converted_amount.toFixed(2)} <span className="text-sm font-normal text-slate-500">{item.to_currency}</span>
                          </span>
                          <span className="text-slate-400 text-xs mt-0.5">
                            Converted from {item.from_currency}
                          </span>
                       </div>
                       <div className="text-right">
                         <div className="text-xs font-mono text-slate-400 bg-slate-50 px-2 py-1 rounded">
                           1 = {item.exchange_rate.toFixed(4)}
                         </div>
                       </div>
                    </div>
                  ))
                )}
             </div>
          )}
        </div>
      </div>

      {/* Supported Currencies Modal */}
      {showCurrencies && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-end sm:items-center justify-center p-0 sm:p-4">
          <div className="bg-white w-full sm:max-w-md max-h-[85vh] rounded-t-3xl sm:rounded-3xl flex flex-col shadow-2xl animate-in slide-in-from-bottom-10">
            <div className="p-4 border-b border-slate-100 flex justify-between items-center">
              <h2 className="text-lg font-bold text-slate-800">Supported Currencies</h2>
              <button 
                onClick={() => setShowCurrencies(false)}
                className="p-2 hover:bg-slate-100 rounded-full transition-colors"
              >
                <X className="w-5 h-5 text-slate-500" />
              </button>
            </div>
            <div className="overflow-y-auto p-4">
              <div className="grid grid-cols-1 gap-2">
                {POPULAR_CURRENCIES.map(curr => (
                  <div key={curr.code} className="flex items-center gap-3 p-3 hover:bg-slate-50 rounded-xl transition-colors">
                    <span className="text-2xl">{curr.flag}</span>
                    <div>
                      <div className="font-bold text-slate-800">{curr.code}</div>
                      <div className="text-xs text-slate-500">{curr.name}</div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;
